    private var engineState: UnsafeMutableRawPointer?
    private var signalSources: [DispatchSourceSignal] = []
    private var toggleInputModeHotKeyRef: EventHotKeyRef?
    private var toggleInputModeSound: NSSound?

    func applicationDidFinishLaunching(_ notification: Notification) {
        print("Activated.")
        installSignalHandler(SIGINT)
        installSignalHandler(SIGTERM)
        initializeEngineState()
        registerToggleInputModeHotKey()
        // Start event tap.
    }

    func applicationWillTerminate(_ notification: Notification) {
        print("Shutting down...")
        // Stop event tap.
        unregisterToggleInputModeHotKey()
        destroyEngineState()
        signalSources.removeAll()
