        guard let state = engineState else {
            return
        }
        state.deallocate()
        engineState = nil
    }

    private func installSignalHandler(_ signalNumber: Int32) {
        signal(signalNumber, SIG_IGN)
        let source = DispatchSource.makeSignalSource(signal: signalNumber, queue: .main)
        source.setEventHandler {
            NSApp.terminate(nil)
        }
        source.resume()
        signalSources.append(source)
    }

    private func registerToggleInputModeHotKey() {
        let selfPointer = Unmanaged.passUnretained(self).toOpaque()
        var eventType = EventTypeSpec(eventClass: OSType(kEventClassKeyboard), eventKind: UInt32(kEventHotKeyPressed))
        InstallEventHandler(
            GetApplicationEventTarget(),
            { _, event, userData -> OSStatus in
                guard let userData else {
                    return OSStatus(eventNotHandledErr)
                }
                var hotKeyId = EventHotKeyID()
                GetEventParameter(
                    event!,
                    EventParamName(kEventParamDirectObject),
                    EventParamType(typeEventHotKeyID),
                    nil,
                    MemoryLayout<EventHotKeyID>.size,
                    nil,
                    &hotKeyId
                )
                if hotKeyId.signature == toggleInputModeHotKeyId.signature &&
                        hotKeyId.id == toggleInputModeHotKeyId.id {
                    let appDelegate = Unmanaged<AppDelegate>
                        .fromOpaque(userData)
                        .takeUnretainedValue()
                    Task { @MainActor in
                            appDelegate.toggleInputMode()
                    }
                }
                return noErr
            },
            1,
            &eventType,
            selfPointer,
            nil
        )
        let id = toggleInputModeHotKeyId
        RegisterEventHotKey(
            UInt32(kVK_Space),
            UInt32(controlKey | optionKey),
            id,
            GetApplicationEventTarget(),
            0,
            &toggleInputModeHotKeyRef
        )
    }

    private func unregisterToggleInputModeHotKey() {
        guard let toggleInputModeHotKeyRef else {
            return
        }
        UnregisterEventHotKey(toggleInputModeHotKeyRef)
        self.toggleInputModeHotKeyRef = nil
    }

    @MainActor
    private func toggleInputMode() {
        appState.mode = appState.mode == .telex ? .literal : .telex
        // TODO: this flow must change when finish integrating with engine.
        toggleInputModeSound?.stop()
        let soundName: NSSound.Name = appState.mode == .telex ? "Pop" : "Tink"
        toggleInputModeSound = NSSound(named: soundName)
        toggleInputModeSound?.play()
    }
